  1→import { useState } from 'react';
  2→import { useProject } from '@/app/ProjectProvider';
  3→import { useEditor } from '@/app/EditorProvider';
  4→import { wallLength } from '@/geometry/wallGeometry';
  5→import InputField from './InputField';
  6→import styles from './PropertiesPanel.module.css';
  7→
  8→function useUnits() {
  9→  const [unit, setUnit] = useState('mm');
 10→  const isMm = unit === 'mm';
 11→  return {
 12→    unit,
 13→    setUnit,
 14→    suffix: isMm ? 'mm' : 'm',
 15→    toDisplay: (mm) => isMm ? Math.round(mm) : +(mm / 1000).toFixed(3),
 16→    fromDisplay: (v) => isMm ? v : v * 1000,
 17→    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
 18→  };
 19→}
