 68→function DoorProperties({ door, wall, dispatch, floorId, editorDispatch, u }) {
 69→  const updateDoor = (updates) => {
 70→    dispatch({ type: 'DOOR_UPDATE', floorId, door: { id: door.id, ...updates } });
 71→  };
 72→
 73→  const doorType = door.type || 'swing';
 74→
 75→  return (
 76→    <div>
 77→      <div className={styles.title}>Door</div>
 78→      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
 79→        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Type</label>
 80→        <select value={doorType} onChange={(e) => updateDoor({ type: e.target.value })}
 81→          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)',
 82→                   borderRadius: 'var(--radius-sm)', fontSize: '12px' }}>
 83→          <option value="swing">Swing</option>
 84→          <option value="double">Double</option>
 85→          <option value="sliding">Sliding</option>
 86→        </select>
 87→      </div>
 88→      <InputField
 89→        label="Width" type="number" suffix={u.suffix} step={u.step(50)}
 90→        value={u.toDisplay(door.width)}
 91→        onChange={(v) => updateDoor({ width: Math.max(400, u.fromDisplay(v)) })}
 92→      />
 93→      <InputField
 94→        label="Offset" type="number" suffix={u.suffix}
 95→        value={u.toDisplay(door.offset)}
 96→        onChange={(v) => updateDoor({ offset: Math.max(0, u.fromDisplay(v)) })}
 97→      />
 98→      {doorType !== 'double' && (
 99→        <>
100→          <InputField
101→            label={doorType === 'sliding' ? 'Slide Dir' : 'Swing'}
102→            value={door.openDirection}
103→            readOnly={false}
104→            onChange={() => updateDoor({
105→              openDirection: door.openDirection === 'left' ? 'right' : 'left',
106→            })}
107→          />
108→          <button
109→            className={styles.deleteBtn}
110→            style={{ marginBottom: '8px', background: 'var(--color-accent)' }}
111→            onClick={() => updateDoor({
112→              openDirection: door.openDirection === 'left' ? 'right' : 'left',
113→            })}
114→          >
115→            {doorType === 'sliding' ? 'Toggle Slide Direction' : 'Toggle Swing Direction'}
116→          </button>
117→        </>
118→      )}
119→      {wall && (
120→        <InputField label="Wall" value={wall.id.split('_').pop()} readOnly />
121→      )}
122→    </div>
123→  );
124→}
