126→function WindowProperties({ window: win, wall, dispatch, floorId, u }) {
127→  const updateWindow = (updates) => {
128→    dispatch({ type: 'WINDOW_UPDATE', floorId, window: { id: win.id, ...updates } });
129→  };
130→
131→  const winType = win.type || 'standard';
132→
133→  return (
